func TestTeach_HappyPathFirstInsert(t *testing.T) {
	t.Parallel()
	db := openRecallTestDB(t)
	inserted, err := Teach(context.Background(), db, testConfig(), TeachInput{
		Query:        "alpha widget",
		ResourceID:   "PREFIX-AL",
		ResourceType: "widgets",
	})
	if err != nil {
		t.Fatalf("teach: %v", err)
	}
	if !inserted {
		t.Errorf("first teach: want inserted=true")
	}
	var count int
	if err := db.QueryRow(`SELECT COUNT(*) FROM search_learnings`).Scan(&count); err != nil {
		t.Fatalf("count: %v", err)
	}
	if count != 1 {
		t.Errorf("learnings count = %d, want 1", count)
	}
}

